import{_ as e,o as t,c as s,a2 as i}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"GTQuiver 箭袋与自定义箭","description":"","frontmatter":{},"headers":[],"relativePath":"gtquiver/index.md","filePath":"gtquiver/index.md","lastUpdated":1783966097000}'),n={name:"gtquiver/index.md"};function l(p,a,d,o,r,h){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="gtquiver-箭袋与自定义箭" tabindex="-1">GTQuiver 箭袋与自定义箭 <a class="header-anchor" href="#gtquiver-箭袋与自定义箭" aria-label="Permalink to &quot;GTQuiver 箭袋与自定义箭&quot;">​</a></h1><p>作者：RusBrook<br> 插件定制：<code>1415375222</code><br> GT 系列插件交流群：<code>985955382</code></p><p>GTQuiver 兼容 1.12.2 - 1.21.11。箭袋内容跟随物品保存，可用于生存服、RPG 服和跨服。</p><h2 id="依赖" tabindex="-1">依赖 <a class="header-anchor" href="#依赖" aria-label="Permalink to &quot;依赖&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>必装</td><td>GTCore</td></tr><tr><td>可选</td><td>PlaceholderAPI、CraneAttribute、AttributePlus、MythicMobs、GTCore 已接入的物品库</td></tr><tr><td>Java</td><td>插件兼容 Java 8，Java 版本仍需满足当前服务端要求</td></tr></tbody></table><p>插件无需授权配置。安装顺序为 GTCore、GTQuiver，依赖和 Jar 有变动时完整重启服务器。</p><h2 id="配置文件" tabindex="-1">配置文件 <a class="header-anchor" href="#配置文件" aria-label="Permalink to &quot;配置文件&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>plugins/GTQuiver/</span></span>
<span class="line"><span>├─ config.yml</span></span>
<span class="line"><span>├─ quivers.yml</span></span>
<span class="line"><span>├─ arrows.yml</span></span>
<span class="line"><span>├─ messages.yml</span></span>
<span class="line"><span>└─ player-settings.yml</span></span></code></pre></div><table tabindex="0"><thead><tr><th>文件</th><th>内容</th></tr></thead><tbody><tr><td><code>config.yml</code></td><td>装备槽、无限附魔、箭回收、属性插件、Lore、GUI、粒子</td></tr><tr><td><code>quivers.yml</code></td><td>箭袋外观、容量、权限、条件、存入规则</td></tr><tr><td><code>arrows.yml</code></td><td>自定义箭物品和命中效果</td></tr><tr><td><code>messages.yml</code></td><td>提示消息</td></tr><tr><td><code>player-settings.yml</code></td><td>玩家执行自动收箭命令后生成</td></tr></tbody></table><p>修改配置后执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtq reload</span></span></code></pre></div><p>配置有误时不会覆盖当前正在使用的配置，具体原因查看控制台。</p><h2 id="发放" tabindex="-1">发放 <a class="header-anchor" href="#发放" aria-label="Permalink to &quot;发放&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtq give &lt;玩家&gt; &lt;箭袋ID&gt; [数量] [bound|unbound]</span></span>
<span class="line"><span>/gtq givearrow &lt;玩家&gt; &lt;箭ID&gt; [数量]</span></span></code></pre></div><p>默认配置带有：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>箭袋：survival、ranger</span></span>
<span class="line"><span>自定义箭：flame、frost</span></span></code></pre></div><p>查看当前已加载 ID：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtq list</span></span></code></pre></div><p>绑定箭袋：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtq give 玩家 survival 1 bound</span></span></code></pre></div><p>非绑定箭袋：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtq give 玩家 survival 1 unbound</span></span></code></pre></div><p>不写模式时默认为非绑定。绑定箭袋只能由绑定玩家拾取和使用，其他玩家不能打开、切箭、射击或作为自动收箭目标。</p><h2 id="玩家操作" tabindex="-1">玩家操作 <a class="header-anchor" href="#玩家操作" aria-label="Permalink to &quot;玩家操作&quot;">​</a></h2><h3 id="打开箭袋" tabindex="-1">打开箭袋 <a class="header-anchor" href="#打开箭袋" aria-label="Permalink to &quot;打开箭袋&quot;">​</a></h3><p>主手拿箭袋：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Shift + 右键空气或方块</span></span></code></pre></div><p>副手拿箭袋不会打开 GUI。</p><h3 id="装备箭袋" tabindex="-1">装备箭袋 <a class="header-anchor" href="#装备箭袋" aria-label="Permalink to &quot;装备箭袋&quot;">​</a></h3><p>默认装备位置是副手：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">settings</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  equipped-slots</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;OFF_HAND&quot;</span></span></code></pre></div><p>也可以改成快捷栏或背包槽位，详见 <a href="/gtquiver/config">config.yml</a>。</p><h3 id="切换箭矢" tabindex="-1">切换箭矢 <a class="header-anchor" href="#切换箭矢" aria-label="Permalink to &quot;切换箭矢&quot;">​</a></h3><p>装备箭袋后：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Shift + 左键空气或方块</span></span></code></pre></div><p>当前箭种会移到其他箭种后面，下一种箭成为首选箭。同一种完整物品会合并为一个箭种，不按堆叠数量重复切换。</p><h2 id="射箭规则" tabindex="-1">射箭规则 <a class="header-anchor" href="#射箭规则" aria-label="Permalink to &quot;射箭规则&quot;">​</a></h2><ul><li>背包已有兼容箭时，按原版规则处理。</li><li>背包没有兼容箭时，从装备箭袋中取箭。</li><li>箭袋按 GUI 从左到右消耗。</li><li>当前箭用完后自动切换下一种。</li><li>普通弓支持普通箭、药水箭、光灵箭。</li><li>弩额外支持烟花火箭。</li><li>无限附魔默认只对无名称、无 Lore、无属性数据的普通原版箭生效。</li><li>创造模式默认不消耗箭袋中的箭。</li></ul><p>箭袋 Lore 会显示总数量、占用槽位、当前箭和箭种明细。</p><h2 id="箭回收" tabindex="-1">箭回收 <a class="header-anchor" href="#箭回收" aria-label="Permalink to &quot;箭回收&quot;">​</a></h2><p>默认禁止拾取射出的箭：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">arrow-recovery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  allow-non-infinity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>改为 <code>true</code> 后，实际消耗且不是无限弓射出的箭可以拾取。玩家装备了可接收该箭的箭袋时，拾取会直接存入箭袋；箭袋放不下时进入普通背包。</p><p>自动收箭默认开启。有权限的玩家可自行切换：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtq autopickup on</span></span>
<span class="line"><span>/gtq autopickup off</span></span></code></pre></div><p>权限：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtquiver.command.autopickup</span></span></code></pre></div><p>该权限默认不授予。</p><h2 id="placeholderapi" tabindex="-1">PlaceholderAPI <a class="header-anchor" href="#placeholderapi" aria-label="Permalink to &quot;PlaceholderAPI&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%gtquiver_current_arrow%</span></span>
<span class="line"><span>%gtquiver_current_arrow_colored%</span></span></code></pre></div><p>第一个返回去色名称，第二个保留物品颜色。没有装备箭袋或箭袋为空时返回 <code>未选择</code>。</p><h2 id="文档" tabindex="-1">文档 <a class="header-anchor" href="#文档" aria-label="Permalink to &quot;文档&quot;">​</a></h2><ul><li><a href="/gtquiver/config">主配置 config.yml</a></li><li><a href="/gtquiver/quivers">箭袋配置 quivers.yml</a></li><li><a href="/gtquiver/arrows">自定义箭 arrows.yml</a></li><li><a href="/gtquiver/compatibility">属性、技能、物品库与变量</a></li><li><a href="/gtquiver/commands">命令与权限</a></li><li><a href="/gtquiver/faq">常见问题</a></li></ul>`,53)])])}const g=e(n,[["render",l]]);export{u as __pageData,g as default};
